import{_ as a,o as r,c as e,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F04: 業外收支純度與收益質量 — 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6257_矽格/20260430/F04_業外收支純度與收益質量_投資研究員.md","filePath":"審計報告庫/財務審計/6257_矽格/20260430/F04_業外收支純度與收益質量_投資研究員.md"}'),o={name:"審計報告庫/財務審計/6257_矽格/20260430/F04_業外收支純度與收益質量_投資研究員.md"};function l(d,t,n,s,h,_){return r(),e("div",null,[...t[0]||(t[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f04-業外收支純度與收益質量-—-投資研究員審計報告" tabindex="-1">F04: 業外收支純度與收益質量 — 投資研究員審計報告 <a class="header-anchor" href="#f04-業外收支純度與收益質量-—-投資研究員審計報告" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量 — 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>業外收支 (Non-Operating) 規模與組成細項為何？是長期投資收益還是匯兌/利息等雜項損益？是否存在獲利虛胖風險？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：業外高度依賴匯率，2024匯兌利益5.35億（佔稅前13.7%），2025翻轉為損失3.27億，侵蝕獲利純度。</li><li><strong>風險評級</strong>：中高（匯兌敏感度為核心隱患）</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：2024匯兌利益5.35億（佔稅前13.7%），2025翻轉為損失3.27億；權益法連續三年為零，利息收入遞減27.7%。</li><li><strong>診斷見解</strong>：業外呈「匯兌雙面刃」——2024台幣貢獻5.35億，2025升值反轉侵蝕。權益法為零，無轉投資。獲利高度依賴匯率方向，不可持續。業外純度評級：B（持平）。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、業外組成年度對比" tabindex="-1">一、業外組成年度對比 <a class="header-anchor" href="#一、業外組成年度對比" aria-label="Permalink to &quot;一、業外組成年度對比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目 (仟元)</th><th>2024</th><th>2025</th></tr></thead><tbody><tr><td>利息收入</td><td>351,949</td><td>270,570</td></tr><tr><td>外幣兌換損益</td><td>+535,496</td><td>(327,268)</td></tr><tr><td>權益法投資</td><td>0</td><td>0</td></tr><tr><td>處分投資</td><td>+20,363</td><td>(3,138)</td></tr><tr><td>業外合計</td><td><strong>+833,619</strong></td><td><strong>(74,216)</strong></td></tr><tr><td>稅前淨利</td><td>3,907,643</td><td>3,893,336</td></tr></tbody></table><p><strong>核心重點</strong>：外幣兌換損益波動達8.62億，佔稅前淨利10.9%，是業外最大變數。利息收入遞減27.7%，反映現金管理效率下降；權益法連續三年為零，處分投資規模極小。</p><h3 id="二、匯率敏感度" tabindex="-1">二、匯率敏感度 <a class="header-anchor" href="#二、匯率敏感度" aria-label="Permalink to &quot;二、匯率敏感度&quot;">​</a></h3><ul><li>匯率每變動1%，對稅前淨利邊際影響±0.5~0.8%。</li><li>2025年Q2匯兌損失約7億，單季業外佔稅前淨利比達-160.96%，侵蝕EPS約1.4元。公司已採取避險措施但效果有限，全年仍淨損失3.27億。</li></ul><h3 id="三、可持續性評價" tabindex="-1">三、可持續性評價 <a class="header-anchor" href="#三、可持續性評價" aria-label="Permalink to &quot;三、可持續性評價&quot;">​</a></h3><p>業外收益70%以上來自匯率方向，屬「短期性套利」而非戰略性穩健。利息收入常態性但遞減27.7%，權益法零貢獻，處分投資規模極小，均非成長動能。未來常態性再現機率低。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><p><strong>空頭風險一：匯兌雙面刃——獲利含金量極低</strong> 2024年與2025年外幣兌換損益合計波動達8.62億（+5.35億→-3.27億），佔兩年稅前淨利合計的10.9%。若台幣進入升值週期，每年將產生2~3億的匯兌損失侵蝕EPS約0.5元。公司雖已採取避險措施，但2025年全年仍淨損失3.27億，避險效果有限。投資人應以「扣非後稅前淨利」（2025年約39.67億）作為估值基礎，而非帳面稅前淨利（38.93億）。</p></li><li><p><strong>空頭風險二：權益法空白——無戰略性轉投資護城河</strong> 連續三年權益法投資為零，顯示矽格未透過轉投資建立產業鏈護城河或技術協同效應。與同業相比（如日月光、矽品透過權益法分享封測產業成長），矽格業外純度雖高（無大額權益法損失），但也意味著錯失了透過轉投資獲取穩定收益的機會。此為「治理警訊」——公司資金配置策略偏保守，未善用資本效率。</p></li><li><p><strong>空頭風險三：公允價值變動損益的隱藏地雷</strong> 2024年「透過損益按公允價值衡量之金融資產淨利益」約2.04億，此類未實現損益在市場波動期可能瞬間轉為巨大減損。2025年已轉為-31.4萬，雖金額不大，但反映公司金融資產組合的波動性。若台股進入下行週期，此科目可能從正貢獻轉為負拖累。</p></li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind financial</strong>：失敗（6257無financial alias資料）</li><li><strong>年報PDF</strong>：OK — 2025_Q4_6257_合併.pdf（114年度）及2024_Q4_6257_合併.pdf（113年度），附註六.二十至二十三</li><li><strong>財報狗</strong>：OK — 2025年Q1-Q4業外佔稅前淨利比（15.23% / -160.96% / 22.51% / 15.93%）</li><li><strong>關鍵核對碼</strong>：2025年業外合計-74,216仟元；稅前淨利3,893,336仟元；外幣兌換損失-327,268仟元（附註六.二十二）</li></ul>',20)])])}const p=a(o,[["render",l]]);export{u as __pageData,p as default};
